import { useState } from 'react';
import { Link } from 'react-router-dom';
import { Clock, ArrowRight, User } from 'lucide-react';

const CATS=['All','Full Stack','Game Development','UI/UX Design','DevOps & Cloud','Careers','Company News'];
const C_COLOR={'Full Stack':'#0057ff','Game Development':'#7c3aed','UI/UX Design':'#db2777','DevOps & Cloud':'#0891b2','Careers':'#059669','Company News':'#d97706'};
const POSTS=[
  {slug:'scalable-rest-apis',img:'https://images.unsplash.com/photo-1555066931-4365d14bab8c?w=700&q=80',title:'Building Scalable REST APIs with Node.js: Best Practices Every Developer Should Know',excerpt:'RESTful APIs are the backbone of modern web apps. We break down the patterns our team follows to keep APIs clean, consistent, and production-ready.',cat:'Full Stack',author:'Synnoviq Engineering',date:'Jan 15, 2025',read:'5 min',tags:['Node.js','REST API','Backend']},
  {slug:'unity-vs-unreal-2025',img:'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?w=700&q=80',title:'Unity vs. Unreal Engine in 2025: Which Is Right for Your Game Project?',excerpt:'Both engines are industry-leading — but serve different purposes. Here\'s how our game team approaches the engine decision for every project.',cat:'Game Development',author:'Synnoviq Game Studio',date:'Feb 3, 2025',read:'7 min',tags:['Unity','Unreal','Game Design']},
  {slug:'internship-experience',img:'https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=700&q=80',title:'From Intern to Engineer: What Our Synnoviq Internship Actually Looks Like',excerpt:'Our internship isn\'t about coffee runs. It\'s about real projects, real code reviews, and real mentorship. Here\'s a typical week for our interns.',cat:'Careers',author:'Synnoviq HR',date:'Mar 10, 2025',read:'4 min',tags:['Internship','Career','Mentorship']},
  {slug:'ux-conversion-mistakes',img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=700&q=80',title:"The 5 UX Mistakes Killing Your Web App's Conversion Rate",excerpt:"Bad UX doesn't just frustrate users — it impacts revenue. Our design team walks through the five most common mistakes they see in client products.",cat:'UI/UX Design',author:'Synnoviq Design',date:'Mar 28, 2025',read:'6 min',tags:['UX','Figma','Conversion']},
  {slug:'cicd-pipelines',img:'https://images.unsplash.com/photo-1667372393119-3d4c48d07fc9?w=700&q=80',title:'CI/CD Pipelines Explained: From Zero to Automated Deployment',excerpt:"Continuous integration and deployment can feel overwhelming. Here's how Synnoviq sets up battle-tested pipelines that let teams ship confidently every day.",cat:'DevOps & Cloud',author:'Synnoviq DevOps',date:'Apr 5, 2025',read:'8 min',tags:['CI/CD','Docker','AWS']},
  {slug:'game-studio-launch',img:'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=700&q=80',title:'Synnoviq Launches Its Dedicated Game Development Studio',excerpt:"We're thrilled to announce the formal launch of our in-house game development studio — what it means for our clients and what we're building next.",cat:'Company News',author:'Synnoviq Team',date:'Apr 20, 2025',read:'3 min',tags:['Announcement','Game Dev']},
];

export default function Blog(){
  const [active,setActive]=useState('All');
  const filtered=active==='All'?POSTS:POSTS.filter(p=>p.cat===active);
  return(
    <div>
      {/* HERO */}
      <section className="img-hero">
        <img className="img-hero-bg" src="https://images.unsplash.com/photo-1499750310107-5fef28a66643?w=1800&q=75" alt="Blog"/>
        <div className="img-hero-dim"/>
        <div className="img-hero-body">
          <div className="wrap">
            <span className="label" style={{color:'rgba(255,255,255,0.5)'}}>Blog & Insights</span>
            <h1 className="t-h1 white anim" style={{maxWidth:700,marginBottom:18}}>Tech Insights &amp; <em className="italic" style={{color:'#5aa8ff'}}>Dev Stories</em></h1>
            <p className="t-lg anim d1" style={{color:'rgba(255,255,255,0.68)',maxWidth:500}}>Tutorials, industry perspectives and deep dives — written by the Synnoviq team.</p>
          </div>
        </div>
      </section>

      <section className="sec">
        <div className="wrap">
          {/* filters */}
          <div style={{display:'flex',flexWrap:'wrap',gap:8,marginBottom:48,justifyContent:'center'}}>
            {CATS.map(c=>(
              <button key={c} onClick={()=>setActive(c)} style={{padding:'8px 16px',borderRadius:999,cursor:'pointer',transition:'all 0.2s',fontFamily:'var(--sans)',fontSize:'0.8rem',fontWeight:600,border:active===c?'none':'1px solid var(--rule)',background:active===c?'var(--ink)':'transparent',color:active===c?'#fff':'var(--ink40)'}}>
                {c}
              </button>
            ))}
          </div>
          <div className="g3">
            {filtered.map(post=>{
              const cc=C_COLOR[post.cat]||'var(--blue)';
              return(
                <article key={post.slug} className="card" style={{display:'flex',flexDirection:'column'}}
                  onMouseEnter={e=>{e.currentTarget.style.boxShadow='var(--sh2)';e.currentTarget.style.transform='translateY(-4px)'}}
                  onMouseLeave={e=>{e.currentTarget.style.boxShadow='none';e.currentTarget.style.transform='translateY(0)'}}
                >
                  <div style={{height:200,overflow:'hidden',position:'relative'}}>
                    <img src={post.img} alt={post.title} style={{width:'100%',height:'100%',objectFit:'cover',transition:'transform 0.4s ease'}}
                      onMouseEnter={e=>e.currentTarget.style.transform='scale(1.06)'}
                      onMouseLeave={e=>e.currentTarget.style.transform='scale(1)'}
                    />
                    <div style={{position:'absolute',inset:0,background:'linear-gradient(to bottom,transparent 40%,rgba(0,0,0,0.28))'}}/>
                    <span style={{position:'absolute',top:12,left:12,padding:'4px 11px',borderRadius:999,background:'rgba(255,255,255,0.95)',color:cc,fontSize:'0.68rem',fontWeight:700,letterSpacing:'0.05em'}}>{post.cat}</span>
                  </div>
                  <div style={{padding:'22px',flex:1,display:'flex',flexDirection:'column'}}>
                    <div style={{display:'flex',gap:14,marginBottom:12}}>
                      <span style={{display:'flex',alignItems:'center',gap:4,color:'var(--ink20)',fontSize:'0.74rem'}}><User size={10}/>{post.author}</span>
                      <span style={{display:'flex',alignItems:'center',gap:4,color:'var(--ink20)',fontSize:'0.74rem'}}><Clock size={10}/>{post.read}</span>
                    </div>
                    <h3 className="t-h3" style={{marginBottom:10,flex:1,display:'-webkit-box',WebkitLineClamp:3,WebkitBoxOrient:'vertical',overflow:'hidden'}}>{post.title}</h3>
                    <p className="t-sm" style={{marginBottom:16,display:'-webkit-box',WebkitLineClamp:2,WebkitBoxOrient:'vertical',overflow:'hidden'}}>{post.excerpt}</p>
                    <div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:14}}>
                      {post.tags.slice(0,3).map(t=><span key={t} style={{padding:'3px 9px',background:'var(--surf)',border:'1px solid var(--rule)',borderRadius:999,fontSize:'0.68rem',fontWeight:600,color:'var(--ink60)'}}>{t}</span>)}
                    </div>
                    <Link to={`/blog/${post.slug}`} style={{display:'inline-flex',alignItems:'center',gap:5,color:cc,fontSize:'0.79rem',fontWeight:700,transition:'gap 0.18s'}}
                      onMouseEnter={e=>e.currentTarget.style.gap='9px'}
                      onMouseLeave={e=>e.currentTarget.style.gap='5px'}
                    >Read More<ArrowRight size={12}/></Link>
                  </div>
                </article>
              );
            })}
          </div>
          {!filtered.length&&<div style={{textAlign:'center',padding:'80px 0',color:'var(--ink40)'}}>No posts in this category yet.</div>}
        </div>
      </section>
    </div>
  );
}
